use std::fmt;

#[derive(Debug)]
pub struct BatchDownloadInfo {
    pub file_sizes: Vec<u64>,
    pub total_size: u64,
    pub file_count: usize,
}

#[derive(Debug)]
pub enum DownloadError {
    InsufficientDiskSpace { required: u64, available: u64 },
    EmptyFileList,
    Overflow,
}

impl fmt::Display for DownloadError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            DownloadError::InsufficientDiskSpace { required, available } => {
                write!(
                    f,
                    "Insufficient disk space: required {} bytes, but only {} bytes available",
                    required, available
                )
            }
            DownloadError::EmptyFileList => write!(f, "No files provided for download"),
            DownloadError::Overflow => write!(f, "Total file size overflowed u64"),
        }
    }
}

impl std::error::Error for DownloadError {}

/// Calculates the total file size using wrapping addition for performance.
/// This is suitable when overflow is not expected (e.g., realistic file sizes).
pub fn calculate_total_size_wrapping(file_sizes: &[u64]) -> u64 {
    file_sizes
        .iter()
        .fold(0u64, |acc, &size| acc.wrapping_add(size))
}

/// Calculates the total file size using checked addition to detect overflow.
pub fn calculate_total_size_checked(file_sizes: &[u64]) -> Result<u64, DownloadError> {
    file_sizes
        .iter()
        .try_fold(0u64, |acc, &size| acc.checked_add(size))
        .ok_or(DownloadError::Overflow)
}

/// Calculates total file size and checks against available disk space.
/// Returns a `BatchDownloadInfo` on success or a `DownloadError` on failure.
pub fn prepare_batch_download(
    file_sizes: Vec<u64>,
    available_disk_space: u64,
) -> Result<BatchDownloadInfo, DownloadError> {
    if file_sizes.is_empty() {
        return Err(DownloadError::EmptyFileList);
    }

    let total_size = calculate_total_size_checked(&file_sizes)?;

    if total_size > available_disk_space {
        return Err(DownloadError::InsufficientDiskSpace {
            required: total_size,
            available: available_disk_space,
        });
    }

    Ok(BatchDownloadInfo {
        file_count: file_sizes.len(),
        file_sizes,
        total_size,
    })
}

/// A high-performance version that uses wrapping_add and skips overflow checks.
/// Use this only when you are confident that the total won't overflow u64
/// (e.g., total is known to be well under 2^64 bytes).
pub fn prepare_batch_download_fast(
    file_sizes: Vec<u64>,
    available_disk_space: u64,
) -> Result<BatchDownloadInfo, DownloadError> {
    if file_sizes.is_empty() {
        return Err(DownloadError::EmptyFileList);
    }

    let total_size = calculate_total_size_wrapping(&file_sizes);

    if total_size > available_disk_space {
        return Err(DownloadError::InsufficientDiskSpace {
            required: total_size,
            available: available_disk_space,
        });
    }

    Ok(BatchDownloadInfo {
        file_count: file_sizes.len(),
        file_sizes,
        total_size,
    })
}

/// Formats bytes into a human-readable string.
pub fn format_size(bytes: u64) -> String {
    const KB: u64 = 1024;
    const MB: u64 = KB * 1024;
    const GB: u64 = MB * 1024;
    const TB: u64 = GB * 1024;

    if bytes >= TB {
        format!("{:.2} TB", bytes as f64 / TB as f64)
    } else if bytes >= GB {
        format!("{:.2} GB", bytes as f64 / GB as f64)
    } else if bytes >= MB {
        format!("{:.2} MB", bytes as f64 / MB as f64)
    } else if bytes >= KB {
        format!("{:.2} KB", bytes as f64 / KB as f64)
    } else {
        format!("{} bytes", bytes)
    }
}

fn main() {
    // Example: batch of files to download
    let file_sizes: Vec<u64> = vec![
        1_073_741_824,  // 1 GB
        536_870_912,    // 512 MB
        2_147_483_648,  // 2 GB
        104_857_600,    // 100 MB
        52_428_800,     // 50 MB
    ];

    let available_space: u64 = 10_737_418_240; // 10 GB

    println!("=== Download Manager - Batch Download Preparation ===\n");
    println!("Available disk space: {}", format_size(available_space));
    println!("Number of files: {}", file_sizes.len());

    for (i, size) in file_sizes.iter().enumerate() {
        println!("  File {}: {}", i + 1, format_size(*size));
    }

    // Using checked (safe) version
    match prepare_batch_download(file_sizes.clone(), available_space) {
        Ok(info) => {
            println!("\n✓ Batch download ready!");
            println!("  Total download size: {}", format_size(info.total_size));
            println!("  Files to download: {}", info.file_count);
            println!(
                "  Remaining space after download: {}",
                format_size(available_space - info.total_size)
            );
        }
        Err(e) => {
            println!("\n✗ Cannot proceed with download: {}", e);
        }
    }

    // Using fast (wrapping) version
    match prepare_batch_download_fast(file_sizes, available_space) {
        Ok(info) => {
            println!("\n✓ [Fast] Batch download ready!");
            println!("  Total download size: {}", format_size(info.total_size));
        }
        Err(e) => {
            println!("\n✗ [Fast] Cannot proceed: {}", e);
        }
    }

    // Demonstrate insufficient space scenario
    println!("\n--- Insufficient Space Scenario ---");
    let large_files: Vec<u64> = vec![5_368_709_120, 5_368_709_120, 5_368_709_120]; // 3 x 5GB
    let small_space: u64 = 10_737_418_240; // 10 GB

    match prepare_batch_download(large_files, small_space) {
        Ok(_info) => println!("Download ready."),
        Err(e) => println!("✗ {}", e),
    }
}

